PAGE = '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>CostSense</title>\n<link href="https://fonts.googleapis.com/css2?family=Syne:wght@400;700&family=IBM+Plex+Mono:wght@400;500&family=IBM+Plex+Sans:wght@300;400;500&display=swap" rel="stylesheet">\n<style>\n*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}\n:root{--bg:#080c10;--sf:#0e1318;--b1:#1c2530;--b2:#243040;--tx:#dce6f0;--mu:#556070;--ac:#00e5ff;--a2:#ff6b35;--gr:#00e090;}\nbody{background:var(--bg);color:var(--tx);font-family:IBM Plex Sans,sans-serif;min-height:100vh}\nbody::before{content:"";position:fixed;inset:0;background-image:linear-gradient(rgba(0,229,255,.03) 1px,transparent 1px),linear-gradient(90deg,rgba(0,229,255,.03) 1px,transparent 1px);background-size:48px 48px;pointer-events:none;z-index:0}\n.wrap{position:relative;z-index:1;max-width:820px;margin:0 auto;padding:48px 24px 80px}\nheader{display:flex;align-items:flex-end;justify-content:space-between;margin-bottom:48px;border-bottom:1px solid var(--b1);padding-bottom:20px}\n.logo{font-family:Syne,sans-serif;font-size:32px;font-weight:700;letter-spacing:-1px}\n.logo span{color:var(--ac)}\n.badge{font-family:IBM Plex Mono,monospace;font-size:11px;color:var(--ac);border:1px solid var(--ac);padding:4px 10px;border-radius:2px;letter-spacing:1px;opacity:.7}\n.uzone{border:1px solid var(--b2);border-radius:4px;padding:40px 32px;display:flex;flex-direction:column;align-items:center;gap:20px;background:rgba(14,19,24,.6);transition:border-color .2s}\n.uzone:hover{border-color:var(--ac)}\n.uicon{width:52px;height:52px;border:1px solid var(--b2);border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:22px}\n.ulabel{font-family:Syne,sans-serif;font-size:17px;font-weight:700;text-align:center}\n.usub{font-size:13px;color:var(--mu);font-family:IBM Plex Mono,monospace}\n.fwrap{position:relative;display:inline-block}\n.fwrap input[type=file]{position:absolute;inset:0;opacity:0;cursor:pointer;width:100%;height:100%}\n.fbtn{display:inline-block;font-family:IBM Plex Mono,monospace;font-size:12px;letter-spacing:1px;padding:10px 24px;border:1px solid var(--b2);border-radius:2px;color:var(--mu);cursor:pointer;transition:all .15s}\n.fbtn:hover{border-color:var(--ac);color:var(--ac)}\n#pvwrap{display:none;flex-direction:column;align-items:center;gap:12px}\n#pvwrap img{max-width:200px;border-radius:4px;border:1px solid var(--b2)}\n.pvname{font-family:IBM Plex Mono,monospace;font-size:12px;color:var(--mu)}\n.price-wrap{display:flex;align-items:center;gap:0;width:100%;max-width:320px;border:1px solid var(--b2);border-radius:3px;overflow:hidden;transition:border-color .2s}\n.price-wrap:focus-within{border-color:var(--ac)}\n.price-prefix{background:var(--b1);color:var(--mu);font-family:IBM Plex Mono,monospace;font-size:13px;padding:11px 14px;white-space:nowrap}\n.price-input{flex:1;background:var(--sf);border:none;color:var(--tx);font-family:IBM Plex Mono,monospace;font-size:15px;padding:11px 14px;outline:none;width:100%}\n.price-input::placeholder{color:var(--mu)}\n.price-hint{font-family:IBM Plex Mono,monospace;font-size:11px;color:var(--mu);margin-top:-8px}\n.abtn{width:100%;margin-top:20px;padding:16px;background:var(--ac);color:#080c10;border:none;border-radius:3px;font-family:Syne,sans-serif;font-size:15px;font-weight:700;cursor:pointer;transition:opacity .15s}\n.abtn:hover{opacity:.85}\n.loader{display:none;flex-direction:column;align-items:center;gap:20px;padding:48px 0}\n.loader.on{display:flex}\n.spin{width:36px;height:36px;border:2px solid var(--b2);border-top-color:var(--ac);border-radius:50%;animation:sp .8s linear infinite}\n@keyframes sp{to{transform:rotate(360deg)}}\n.slist{display:flex;flex-direction:column;gap:10px;width:280px}\n.si{display:flex;align-items:center;gap:10px;font-family:IBM Plex Mono,monospace;font-size:12px;color:var(--mu);transition:color .3s}\n.si.active{color:var(--ac)}.si.done{color:var(--gr)}\n.dot{width:6px;height:6px;border-radius:50%;background:var(--b2);flex-shrink:0;transition:background .3s}\n.si.active .dot{background:var(--ac)}.si.done .dot{background:var(--gr)}\n#results{display:none;flex-direction:column;gap:16px}\n#results.on{display:flex;animation:up .4s ease both}\n@keyframes up{from{opacity:0;transform:translateY(14px)}to{opacity:1;transform:translateY(0)}}\n.slabel{font-family:IBM Plex Mono,monospace;font-size:11px;letter-spacing:2px;color:var(--mu);text-transform:uppercase;margin:20px 0 8px}\n.card{background:var(--sf);border:1px solid var(--b1);border-radius:4px;padding:22px 24px;position:relative}\n.card::before{content:attr(data-n);position:absolute;right:20px;top:14px;font-family:IBM Plex Mono,monospace;font-size:11px;color:var(--b2);letter-spacing:1px}\n.ctitle{font-family:IBM Plex Mono,monospace;font-size:11px;letter-spacing:2px;text-transform:uppercase;color:var(--mu);margin-bottom:10px}\n.cbody{font-size:14px;line-height:1.8;color:#a8b8c8}\n.cbody ul{list-style:none;padding:0}\n.cbody ul li{padding:4px 0 4px 16px;position:relative}\n.cbody ul li::before{content:"--";position:absolute;left:0;color:var(--mu);font-family:IBM Plex Mono,monospace}\n.itext{font-family:Syne,sans-serif;font-size:18px;font-weight:500;color:var(--a2);line-height:1.5}\n.phead{display:flex;gap:20px;align-items:flex-start;background:var(--sf);border:1px solid var(--b1);border-radius:4px;padding:20px 24px}\n.pimg{width:80px;height:80px;object-fit:cover;border-radius:3px;border:1px solid var(--b1);flex-shrink:0}\n.pname{font-family:Syne,sans-serif;font-size:20px;font-weight:700;text-transform:capitalize;margin-bottom:6px}\n.psub{font-family:IBM Plex Mono,monospace;font-size:12px;color:var(--mu)}\n.scard{background:var(--sf);border:1px solid var(--b1);border-radius:4px;padding:22px 24px}\n.srow{display:flex;align-items:baseline;gap:12px;margin-bottom:20px;flex-wrap:wrap}\n.sbefore{font-family:IBM Plex Mono,monospace;font-size:26px;color:var(--mu);text-decoration:line-through}\n.sarrow{font-size:18px;color:var(--mu)}\n.safter{font-family:IBM Plex Mono,monospace;font-size:34px;font-weight:500;color:var(--gr)}\n.stag{margin-left:auto;background:rgba(0,224,144,.08);border:1px solid rgba(0,224,144,.25);color:var(--gr);font-family:IBM Plex Mono,monospace;font-size:12px;padding:4px 12px;border-radius:2px}\n.track{height:4px;background:var(--b1);border-radius:2px;overflow:hidden}\n.fill{height:100%;background:linear-gradient(90deg,var(--gr),var(--ac));border-radius:2px;width:0;transition:width 1.2s cubic-bezier(.22,1,.36,1)}\n.plabel{display:flex;justify-content:space-between;margin-top:8px;font-family:IBM Plex Mono,monospace;font-size:11px;color:var(--mu)}\n.rbtn{background:transparent;border:1px solid var(--b2);color:var(--mu);font-family:IBM Plex Mono,monospace;font-size:12px;padding:10px 20px;border-radius:2px;cursor:pointer;letter-spacing:1px;transition:all .15s;margin-top:8px}\n.rbtn:hover{border-color:var(--ac);color:var(--ac)}\n.hpanel{margin-top:48px;border-top:1px solid var(--b1);padding-top:32px}\n.htitle{font-family:IBM Plex Mono,monospace;font-size:11px;letter-spacing:2px;color:var(--mu);text-transform:uppercase;margin-bottom:16px}\n.hgrid{display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:12px}\n.hcard{background:var(--sf);border:1px solid var(--b1);border-radius:4px;padding:14px;cursor:pointer;transition:border-color .2s}\n.hcard:hover{border-color:var(--ac)}\n.hcard img{width:100%;height:90px;object-fit:cover;border-radius:3px;margin-bottom:10px}\n.hpname{font-family:Syne,sans-serif;font-size:13px;font-weight:700;text-transform:capitalize;margin-bottom:4px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}\n.hissue{font-size:11px;color:var(--mu);line-height:1.5;overflow:hidden;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical}\n.hbadge{display:inline-block;margin-top:8px;font-family:IBM Plex Mono,monospace;font-size:11px;color:var(--gr);background:rgba(0,224,144,.08);border:1px solid rgba(0,224,144,.2);padding:2px 8px;border-radius:2px}\n.hempty{font-family:IBM Plex Mono,monospace;font-size:12px;color:var(--mu);padding:20px 0}\n</style>\n</head>\n<body>\n<div class="wrap">\n  <header>\n    <div class="logo">Cost<span>Sense</span></div>\n    <div class="badge">AI &middot; COST ANALYSIS</div>\n  </header>\n  <div id="usec">\n    <div class="uzone">\n      <div class="uicon">&#128230;</div>\n      <div class="ulabel">Drop a product image to analyze</div>\n      <div class="usub">JPG &middot; PNG &middot; WEBP</div>\n      <div class="fwrap">\n        <div class="fbtn">CHOOSE FILE</div>\n        <input type="file" accept="image/*" id="finput">\n      </div>\n      <div id="pvwrap">\n        <img id="pvimg" src="" alt="preview">\n        <div class="pvname" id="pvname"></div>\n      </div>\n      <div class="price-wrap">\n        <div class="price-prefix">Rs.</div>\n        <input class="price-input" type="number" id="priceinput" placeholder="Product price" min="1">\n      </div>\n      <div class="price-hint">AI will calculate your optimized price based on this</div>\n    </div>\n    <button class="abtn" id="abtn">Analyze Cost &rarr;</button>\n  </div>\n  <div class="loader" id="ldr">\n    <div class="spin"></div>\n    <div class="slist">\n      <div class="si" id="s1"><div class="dot"></div>Identifying product via BLIP</div>\n      <div class="si" id="s2"><div class="dot"></div>Detecting components &amp; drivers</div>\n      <div class="si" id="s3"><div class="dot"></div>Diagnosing key issue</div>\n      <div class="si" id="s4"><div class="dot"></div>Generating recommendations</div>\n      <div class="si" id="s5"><div class="dot"></div>Calculating savings</div>\n    </div>\n  </div>\n  <div id="results">\n    <div class="slabel">Analysis Report</div>\n    <div class="phead">\n      <img class="pimg" id="rimg" src="" alt="">\n      <div>\n        <div class="pname" id="rprod"></div>\n        <div class="psub">Identified via BLIP image captioning</div>\n      </div>\n    </div>\n    <div class="card" data-n="01">\n      <div class="ctitle">Key Issue</div>\n      <div class="itext" id="rissue"></div>\n    </div>\n    <div class="card" data-n="02">\n      <div class="ctitle">Components &amp; Cost Drivers</div>\n      <div class="cbody" id="rcomp"></div>\n    </div>\n    <div class="card" data-n="03">\n      <div class="ctitle">Recommendations</div>\n      <div class="cbody" id="rsol"></div>\n    </div>\n    <div class="scard">\n      <div class="ctitle">Savings Opportunity</div>\n      <div class="srow">\n        <div class="sbefore" id="rbefore"></div>\n        <div class="sarrow">&rarr;</div>\n        <div class="safter" id="rafter"></div>\n        <div class="stag" id="rtag"></div>\n      </div>\n      <div class="track"><div class="fill" id="rbar"></div></div>\n      <div class="plabel"><span>Cost reduction based on your price</span><span id="rpct"></span></div>\n    </div>\n    <button class="rbtn" id="rbtn">&larr; Analyze Another</button>\n  </div>\n  <div class="hpanel">\n    <div class="htitle">Past Analyses</div>\n    <div class="hgrid" id="hgrid"><div class="hempty">No analyses yet.</div></div>\n  </div>\n</div>\n<script>\nvar purl = "";\nvar sids = ["s1","s2","s3","s4","s5"];\nvar stmr = null;\n\nfunction G(id) { return document.getElementById(id); }\n\nG("finput").onchange = function() {\n  var f = this.files[0];\n  if (!f) return;\n  var r = new FileReader();\n  r.onload = function(e) {\n    purl = e.target.result;\n    G("pvimg").src = purl;\n    G("pvname").textContent = f.name;\n    G("pvwrap").style.display = "flex";\n  };\n  r.readAsDataURL(f);\n};\n\nG("abtn").onclick = function() {\n  var f = G("finput").files[0];\n  if (!f) { alert("Please select an image first."); return; }\n  var price = parseFloat(G("priceinput").value);\n  if (!price || price <= 0) { alert("Please enter a valid product price."); return; }\n  G("usec").style.display = "none";\n  G("ldr").classList.add("on");\n  G("results").classList.remove("on");\n  startS();\n  var fd = new FormData();\n  fd.append("image", f);\n  fd.append("price", price);\n  fetch("/analyze", { method: "POST", body: fd })\n    .then(function(res) { return res.json(); })\n    .then(function(d) {\n      stopS();\n      if (d.error) { alert("Error: " + d.error); doReset(); return; }\n      var before = price;\n      var after = Math.round(price * (1 - d.percent / 100));\n      var savings = Math.round(price * d.percent / 100);\n      showResult(d, purl, before, after, savings);\n      loadHistory();\n    })\n    .catch(function(e) { alert("Error: " + e.message); doReset(); });\n};\n\nG("rbtn").onclick = doReset;\n\nfunction showResult(d, imgSrc, before, after, savings) {\n  G("rimg").src = imgSrc;\n  G("rprod").textContent = d.product;\n  G("rissue").textContent = d.issue;\n  G("rcomp").innerHTML = toList(d.components);\n  G("rsol").innerHTML = toList(d.solution);\n  G("rbefore").textContent = "Rs." + before;\n  G("rafter").textContent = "Rs." + after;\n  G("rtag").textContent = d.percent + "% saved  (Rs." + savings + ")";\n  G("rpct").textContent = d.percent + "%";\n  G("ldr").classList.remove("on");\n  G("results").classList.add("on");\n  G("rbar").style.width = "0%";\n  setTimeout(function() { G("rbar").style.width = d.percent + "%"; }, 200);\n}\n\nfunction toList(t) {\n  if (!t) return "";\n  var lines = t.split("\\n");\n  var h = "<ul>";\n  for (var i = 0; i < lines.length; i++) {\n    var line = lines[i].trim();\n    line = line.replace(/^[0-9]+\\. /, "").replace(/^[-*] /, "");\n    if (line) h += "<li>" + line + "</li>";\n  }\n  return h + "</ul>";\n}\n\nfunction startS() {\n  var i = 0;\n  function tick() {\n    if (i > 0) G(sids[i-1]).className = "si done";\n    if (i < sids.length) { G(sids[i]).className = "si active"; i++; stmr = setTimeout(tick, 2200); }\n  }\n  tick();\n}\n\nfunction stopS() {\n  clearTimeout(stmr);\n  for (var i = 0; i < sids.length; i++) G(sids[i]).className = "si done";\n}\n\nfunction doReset() {\n  clearTimeout(stmr);\n  for (var i = 0; i < sids.length; i++) G(sids[i]).className = "si";\n  G("ldr").classList.remove("on");\n  G("results").classList.remove("on");\n  G("usec").style.display = "block";\n  G("pvwrap").style.display = "none";\n  G("finput").value = "";\n  G("priceinput").value = "";\n  G("rbar").style.width = "0%";\n  purl = "";\n}\n\nfunction loadHistory() {\n  fetch("/history")\n    .then(function(res) { return res.json(); })\n    .then(function(items) {\n      var g = G("hgrid");\n      if (!items || items.length === 0) {\n        g.innerHTML = "<div class=hempty>No analyses yet.</div>";\n        return;\n      }\n      g.innerHTML = "";\n      for (var i = 0; i < items.length; i++) {\n        (function(d) {\n          var c = document.createElement("div");\n          c.className = "hcard";\n          var img = document.createElement("img");\n          img.src = d.image_b64;\n          var nm = document.createElement("div");\n          nm.className = "hpname";\n          nm.textContent = d.product;\n          var iss = document.createElement("div");\n          iss.className = "hissue";\n          iss.textContent = d.issue;\n          var badge = document.createElement("div");\n          badge.className = "hbadge";\n          badge.textContent = d.percent + "% savings";\n          c.appendChild(img);\n          c.appendChild(nm);\n          c.appendChild(iss);\n          c.appendChild(badge);\n          c.onclick = function() {\n            showResult(d, d.image_b64, d.before, d.after, d.before - d.after);\n          };\n          g.appendChild(c);\n        })(items[i]);\n      }\n    })\n    .catch(function() {});\n}\n\nloadHistory();\n</script>\n</body>\n</html>\n'


